// Writing to file
#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Create and open file for writing
 ofstream outFile("sample.txt");

 if (!outFile) {
 cerr << "Error: Could not open file for writing" << endl;
 return 1;
 }

 // Write formatted data
 outFile << "Name: John Doe" << endl;
 outFile << "Age: 25" << endl;
 outFile << "Score: 95.5" << endl;

 outFile.close();

 // Reading from file
 ifstream inFile("sample.txt");

 if (!inFile) {
 cerr << "Error: Could not open file for reading" << endl;
 return 1;
 }

 string line;
 while (getline(inFile, line)) {
 cout << line << endl;
 }

 // Check why reading stopped
 if (inFile.eof()) {
 cout << "End of file reached" << endl;
 } else if (inFile.fail()) {
 cout << "Read operation failed" << endl;
 }

 inFile.close();
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

struct Student {
 char name[30];
 int rollNo;
 float marks;
};

int main() {
 // Create sample student data
 Student s1 = {"Alice", 1, 95.5f};
 Student s2 = {"Bob", 2, 87.0f};
 Student s3 = {"Charlie", 3, 92.25f};

 // Open file for binary writing
 fstream file("students.dat", ios::out | ios::binary | ios::trunc);

 if (!file) {
 cerr << "Cannot open file!" << endl;
 return 1;
 }

 // Write student records
 file.write(reinterpret_cast<char*>(&s1), sizeof(Student));
 file.write(reinterpret_cast<char*>(&s2), sizeof(Student));
 file.write(reinterpret_cast<char*>(&s3), sizeof(Student));

 file.close();

 // Reopen for reading with random access
 file.open("students.dat", ios::in | ios::binary);

 Student s;

 // Read second record directly (skip first)
 file.seekg(sizeof(Student), ios::beg); // Move to 2nd record
 file.read(reinterpret_cast<char*>(&s), sizeof(Student));

 cout << "Second Student: " << s.name 
 << ", Roll: " << s.rollNo 
 << ", Marks: " << s.marks << endl;

 // Read third record (skip second)
 file.seekg(2 * sizeof(Student), ios::beg);
 file.read(reinterpret_cast<char*>(&s), sizeof(Student));

 cout << "Third Student: " << s.name 
 << ", Roll: " << s.rollNo 
 << ", Marks: " << s.marks << endl;

 file.close();
 return 0;
}

#include <fstream>
#include <iostream>
#include <sstream>
using namespace std;

int main() {
 // Formatted I/O - automatic type conversion
 ostringstream oss;
 int num = 42;
 double pi = 3.14159;
 string name = "Test";

 // Insertion operator does automatic conversion
 oss << "Number: " << num << endl;
 oss << "Pi: " << pi << endl;
 oss << "Name: " << name << endl;

 cout << "=== Formatted Output ===" << endl;
 cout << oss.str();

 // Unformatted I/O - raw character access
 string input = "Hello World";
 istringstream iss(input);

 cout << "\n=== Unformatted Input (char by char) ===" << endl;
 char c;
 while (iss.get(c)) {
 if (c == ' ') cout << "[space]";
 else cout << c;
 }

 // Reset and try getline
 iss.clear();
 iss.str(input);

 cout << "\n\n=== Using getline (unformatted) ===" << endl;
 string word;
 while (getline(iss, word, ' ')) {
 cout << "Word: '" << word << "'" << endl;
 }

 // Unformatted output with put() and write()
 cout << "\n=== Unformatted Output ===" << endl;
 char msg[] = "Direct bytes";
 cout.write(msg, 5); // Write first 5 bytes
 cout.put('\n');
 cout.write(msg + 5, 6); // Write remaining bytes
 cout << endl;

 return 0;
}
